BX.Aspro.Utils.readyDOM(()=>{const detailTextBlock=document.querySelector(".partner-detail__text");if(detailTextBlock.scrollHeight>detailTextBlock.clientHeight){const nodeDetailSpoiler=document.querySelector(".partner-detail__spoiler");nodeDetailSpoiler&&nodeDetailSpoiler.classList.remove("hide");const nodeDetailSpoilerButton=nodeDetailSpoiler.querySelector("._choise");if(nodeDetailSpoilerButton){const nodeDetailText=document.querySelector(".partner-detail__text");BX.bind(nodeDetailSpoilerButton,"click",(function(){this.classList.toggle("show"),nodeDetailText.classList.toggle("lineclamp-4")}))}}});